={{
  (() => {
    let raw = $('Variáveis do Fluxo').item.json.botPhoneNumber || "";

    // Remove tudo que não é número
    let num = raw.replace(/\D/g, "");

    // Garante que começa com 55
    if (!num.startsWith("55")) {
      num = "55" + num;
    }

    // Depois do 55, 10 dígitos = número sem 9
    // 55 + DDD(2) + número(8) = 12 dígitos TOTAL
    if (num.length === 12) {
      let pais = num.slice(0, 2); // 55
      let ddd = num.slice(2, 4);  // ex: 67
      let base = num.slice(4);    // ex: 92190178 (8 dígitos)
      num = pais + ddd + "9" + base;
    }

    return "+" + num;
  })()
}}

